+    /// Enable self-speculative drafting mode
+    /// Pins VIP experts (0, 4) for ALL 32 layers into RAM (~5.3GB)
+    /// After this call, drafting uses RAM-speed VIP experts (200 GB/s)
+    pub fn enableSelfSpeculativeDrafting(self: *Self) !void {
+        if (self.self_speculative_enabled) {
+            log.info("Self-speculative drafting already enabled", .{});
+            return;
+        }
+
+        log.info("Enabling Self-Speculative Drafting...", .{});
+        log.info("  Pinning VIP experts (0, 4) for all 32 layers (~5.3GB)", .{});
+
+        // Pre-load VIP experts for all 32 layers
+        try self.preloadAllVIPExperts();
+
+        self.self_speculative_enabled = true;
+        log.info("Self-Speculative Drafting ENABLED", .{});
+        log.info("  Draft phase: VIP experts (0, 4) → RAM speed (200 GB/s)", .{});
+        log.info("  Verify phase: Real router → 80%% RAM, 20%% SSD", .{});
+        logMemoryUsage("after_self_spec_enabled");
+    }
+
+    /// Pre-load VIP experts (0 and 4) for ALL 32 layers into RAM
+    /// This is the key to self-speculative drafting - RAM-resident VIP weights
+    ///
+    /// Memory: 2 experts × 32 layers × 3 tensors × ~27MB/tensor = ~5.3GB
+    pub fn preloadAllVIPExperts(self: *Self) !void {
+        if (self.vip_experts_preloaded) {
+            log.info("VIP experts already pre-loaded", .{});
+            return;
+        }
+
+        const VIP_EXPERTS = [_]u32{ 0, 4 };
+        var loaded_count: usize = 0;
+        var loaded_bytes: usize = 0;
+
+        // Initialize mmap base pointer if needed
+        if (self.moe_engine.mmap_base_ptr == null) {
+            const mmap_ptr: [*]u8 = @ptrCast(@constCast(self.loader.mmap_ptr));
+            self.moe_engine.initMmapBase(mmap_ptr, self.loader.mmap_len);
+        }
+
+        log.info("Pre-loading VIP experts (0, 4) for all 32 layers...", .{});
+
+        var name_buf: [64]u8 = undefined;
+
+        for (0..32) |layer| {
+            for (VIP_EXPERTS) |expert| {
+                // Gate tensor
+                const gate_name = std.fmt.bufPrint(&name_buf, "blk.{d}.ffn_gate.{d}.weight", .{ layer, expert }) catch continue;
+                if (self.loader.getTensorOffsetAndSize(gate_name)) |info| {
+                    if (self.moe_engine.getOrCreateTensorBuffer(gate_name, info.offset, info.size)) |_| {
+                        loaded_count += 1;
+                        loaded_bytes += info.size;
+                    } else |_| {}
+                }
+
+                // Up tensor
+                const up_name = std.fmt.bufPrint(&name_buf, "blk.{d}.ffn_up.{d}.weight", .{ layer, expert }) catch continue;
+                if (self.loader.getTensorOffsetAndSize(up_name)) |info| {
+                    if (self.moe_engine.getOrCreateTensorBuffer(up_name, info.offset, info.size)) |_| {
+                        loaded_count += 1;
+                        loaded_bytes += info.size;
+                    } else |_| {}
+                }
+
+                // Down tensor
+                const down_name = std.fmt.bufPrint(&name_buf, "blk.{d}.ffn_down.{d}.weight", .{ layer, expert }) catch continue;
+                if (self.loader.getTensorOffsetAndSize(down_name)) |info| {
+                    if (self.moe_engine.getOrCreateTensorBuffer(down_name, info.offset, info.size)) |_| {
+                        loaded_count += 1;
+                        loaded_bytes += info.size;
+                    } else |_| {}
+                }
+            }
+        }
+
+        self.vip_experts_preloaded = true;
+        const loaded_mb = loaded_bytes / (1024 * 1024);
+        log.info("VIP experts pre-loaded: {} tensors ({} MB RAM-resident)", .{ loaded_count, loaded_mb });
+        logMemoryUsage("after_vip_preload");
+    }
+
+    /// Draft tokens using self-speculative mode (VIP experts only, RAM speed)
+    /// Uses the SAME main model with forced VIP expert routing
+    /// Returns number of tokens drafted (up to draft_buf.len)
+    pub fn draftSelfSpeculative(self: *Self, draft_buf: []u32, last_token: u32, pos: u32) !usize {
+        if (!self.self_speculative_enabled) return 0;
+
+        var drafted: usize = 0;
+        var current_token = last_token;
+        var current_pos = pos;
+
+        while (drafted < draft_buf.len) {
+            // Forward uses VIP experts (0, 4) - already hardcoded in forwardTrueSingleSubmit
+            // Since VIP experts are pre-loaded in RAM, this runs at RAM speed
+            const logits = try self.forwardTrueSingleSubmit(current_token, current_pos);
+
+            // Greedy sample next token
+            const next_token = self.sampleGreedy(logits);
+
+            // Check for EOS (token 2 in Mixtral)
+            if (next_token == 2) {
+                break;
+            }
+
+            draft_buf[drafted] = next_token;
+            drafted += 1;
+
+            current_token = next_token;
+            current_pos += 1;
+        }
+
+        return drafted;
+    }
